//! Centralizes setup/teardown lifecycle management across all granularity levels.
//!
//! The [`SetupManager`] tracks active setup contexts (session, file, function,
//! execution), records failures per level, and decides whether to skip setup
//! when a prior failure makes further attempts futile.

use std::collections::HashMap;
use std::time::Duration;

use crate::protocol::{SetupContextEntry, SetupContextStack, SetupLevel};

// ---------------------------------------------------------------------------
// Timeout defaults — one per lifecycle level
// ---------------------------------------------------------------------------

/// Default timeout for session-level setup/teardown (120 seconds).
pub const DEFAULT_SESSION_TIMEOUT_SECS: u64 = 120;

/// Default timeout for file-level setup/teardown (30 seconds).
pub const DEFAULT_FILE_TIMEOUT_SECS: u64 = 30;

/// Default timeout for function-level setup/teardown (15 seconds).
pub const DEFAULT_FUNCTION_TIMEOUT_SECS: u64 = 15;

/// Default timeout for execution-level setup/teardown (5 seconds).
pub const DEFAULT_EXECUTION_TIMEOUT_SECS: u64 = 5;

/// Environment variable that overrides all setup timeouts with a single value (seconds).
pub const SETUP_TIMEOUT_ENV_VAR: &str = "SHATTER_SETUP_TIMEOUT";

// ---------------------------------------------------------------------------
// SetupTimeouts
// ---------------------------------------------------------------------------

/// Per-level timeout durations for setup/teardown operations.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SetupTimeouts {
    pub session: Duration,
    pub file: Duration,
    pub function: Duration,
    pub execution: Duration,
}

impl Default for SetupTimeouts {
    fn default() -> Self {
        Self {
            session: Duration::from_secs(DEFAULT_SESSION_TIMEOUT_SECS),
            file: Duration::from_secs(DEFAULT_FILE_TIMEOUT_SECS),
            function: Duration::from_secs(DEFAULT_FUNCTION_TIMEOUT_SECS),
            execution: Duration::from_secs(DEFAULT_EXECUTION_TIMEOUT_SECS),
        }
    }
}

impl SetupTimeouts {
    /// Build timeouts from defaults, then apply `SHATTER_SETUP_TIMEOUT` env var
    /// if present and valid. Invalid values (non-numeric, zero, negative) are
    /// silently ignored, matching the timeout contract used elsewhere in Shatter.
    pub fn from_env() -> Self {
        let mut timeouts = Self::default();
        if let Ok(val) = std::env::var(SETUP_TIMEOUT_ENV_VAR) {
            if let Ok(secs) = val.parse::<u64>() {
                if secs > 0 {
                    let dur = Duration::from_secs(secs);
                    timeouts.session = dur;
                    timeouts.file = dur;
                    timeouts.function = dur;
                    timeouts.execution = dur;
                }
            }
        }
        timeouts
    }

    /// Return the timeout for a specific level.
    pub fn timeout_for(&self, level: SetupLevel) -> Duration {
        match level {
            SetupLevel::Session => self.session,
            SetupLevel::File => self.file,
            SetupLevel::Function => self.function,
            SetupLevel::Execution => self.execution,
        }
    }
}

// ---------------------------------------------------------------------------
// SetupFailures
// ---------------------------------------------------------------------------

/// Tracks setup failures per level so callers can decide whether to retry or skip.
#[derive(Debug, Clone, Default)]
pub struct SetupFailures {
    failures: HashMap<SetupLevel, Vec<SetupFailureRecord>>,
}

/// A single recorded setup failure.
#[derive(Debug, Clone)]
pub struct SetupFailureRecord {
    pub level: SetupLevel,
    pub message: String,
    pub scope: String,
}

impl SetupFailures {
    pub fn new() -> Self {
        Self::default()
    }

    /// Record a failure for the given level and scope.
    pub fn record(&mut self, level: SetupLevel, scope: String, message: String) {
        self.failures
            .entry(level)
            .or_default()
            .push(SetupFailureRecord {
                level,
                message,
                scope,
            });
    }

    /// Check whether the given level has any recorded failures.
    pub fn has_failures(&self, level: SetupLevel) -> bool {
        self.failures
            .get(&level)
            .is_some_and(|records| !records.is_empty())
    }

    /// Return failure records for a given level (empty slice if none).
    pub fn failures_for(&self, level: SetupLevel) -> &[SetupFailureRecord] {
        self.failures.get(&level).map_or(&[], |v| v.as_slice())
    }

    /// Total number of recorded failures across all levels.
    pub fn total(&self) -> usize {
        self.failures.values().map(|v| v.len()).sum()
    }

    /// Clear all failure records.
    pub fn clear(&mut self) {
        self.failures.clear();
    }
}

// ---------------------------------------------------------------------------
// Error types
// ---------------------------------------------------------------------------

/// Errors produced by setup/teardown operations.
#[derive(Debug, thiserror::Error)]
pub enum SetupError {
    #[error("setup failed at {level:?} for scope '{scope}': {message}")]
    Failed {
        level: SetupLevel,
        scope: String,
        message: String,
    },

    #[error("setup timed out at {level:?} for scope '{scope}' after {timeout:?}")]
    Timeout {
        level: SetupLevel,
        scope: String,
        timeout: Duration,
    },

    #[error("setup skipped at {level:?} for scope '{scope}': prior failure at {failed_level:?}")]
    Skipped {
        level: SetupLevel,
        scope: String,
        failed_level: SetupLevel,
    },
}

// ---------------------------------------------------------------------------
// SetupManager
// ---------------------------------------------------------------------------

/// Centralizes setup lifecycle: context caches per level, failure tracking,
/// and skip decisions. Each level's context cache holds the opaque
/// `serde_json::Value` returned by the frontend's Setup response.
#[derive(Debug)]
pub struct SetupManager {
    /// Cached setup context per level. Only one active context per level —
    /// calling setup at the same level replaces the previous context.
    contexts: HashMap<SetupLevel, serde_json::Value>,

    /// Failure tracker.
    pub failures: SetupFailures,

    /// Per-level timeout configuration.
    pub timeouts: SetupTimeouts,

    /// When true, any setup failure immediately propagates as an error rather
    /// than being recorded for later skip decisions.
    pub fail_on_error: bool,
}

impl Default for SetupManager {
    fn default() -> Self {
        Self::new(SetupTimeouts::default(), false)
    }
}

impl SetupManager {
    pub fn new(timeouts: SetupTimeouts, fail_on_error: bool) -> Self {
        Self {
            contexts: HashMap::new(),
            failures: SetupFailures::new(),
            timeouts,
            fail_on_error,
        }
    }

    /// Convenience constructor that reads timeouts from env and uses provided
    /// `fail_on_error` setting.
    pub fn from_env(fail_on_error: bool) -> Self {
        Self::new(SetupTimeouts::from_env(), fail_on_error)
    }

    // -- Setup / Teardown ---------------------------------------------------

    /// Record a successful setup at the given level, caching its context.
    /// Returns an error if the level should be skipped due to a prior failure
    /// at a higher (outer) level.
    pub fn setup(
        &mut self,
        level: SetupLevel,
        scope: &str,
        context: serde_json::Value,
    ) -> Result<(), SetupError> {
        if let Some(failed_level) = self.blocking_failure(level) {
            return Err(SetupError::Skipped {
                level,
                scope: scope.to_owned(),
                failed_level,
            });
        }
        self.contexts.insert(level, context);
        Ok(())
    }

    /// Record a setup failure. When `fail_on_error` is true the error is
    /// returned immediately; otherwise it is recorded for later skip checks.
    pub fn record_failure(
        &mut self,
        level: SetupLevel,
        scope: &str,
        message: String,
    ) -> Result<(), SetupError> {
        self.failures
            .record(level, scope.to_owned(), message.clone());
        if self.fail_on_error {
            return Err(SetupError::Failed {
                level,
                scope: scope.to_owned(),
                message,
            });
        }
        Ok(())
    }

    /// Tear down a level: removes its cached context and all inner levels.
    /// For example, tearing down `File` also clears `Function` and `Execution`.
    pub fn teardown(&mut self, level: SetupLevel) {
        for lvl in levels_from(level) {
            self.contexts.remove(&lvl);
        }
    }

    // -- Query --------------------------------------------------------------

    /// Return the current context stack ordered from outermost (session) to
    /// innermost (execution), including only levels that have active contexts.
    pub fn context_stack(&self) -> SetupContextStack {
        let contexts = LEVEL_ORDER
            .iter()
            .filter_map(|&lvl| {
                self.contexts.get(&lvl).map(|ctx| SetupContextEntry {
                    level: lvl,
                    context: ctx.clone(),
                })
            })
            .collect();
        SetupContextStack { contexts }
    }

    /// Check whether setup at the given level should be skipped.
    /// A level is skipped when it or any outer level has a recorded failure.
    pub fn should_skip(&self, level: SetupLevel) -> bool {
        self.blocking_failure(level).is_some()
    }

    /// Return the cached context for a specific level, if any.
    pub fn context_for(&self, level: SetupLevel) -> Option<&serde_json::Value> {
        self.contexts.get(&level)
    }

    /// Return the timeout for a specific level.
    pub fn timeout_for(&self, level: SetupLevel) -> Duration {
        self.timeouts.timeout_for(level)
    }

    /// True when any level has an active context.
    pub fn has_active_contexts(&self) -> bool {
        !self.contexts.is_empty()
    }

    // -- Internal -----------------------------------------------------------

    /// Find the outermost level (including `level` itself) that has a failure,
    /// making `level` un-runnable.
    fn blocking_failure(&self, level: SetupLevel) -> Option<SetupLevel> {
        for &lvl in &LEVEL_ORDER {
            if self.failures.has_failures(lvl) {
                return Some(lvl);
            }
            if lvl == level {
                break;
            }
        }
        None
    }
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/// Canonical ordering from outermost to innermost.
const LEVEL_ORDER: [SetupLevel; 4] = [
    SetupLevel::Session,
    SetupLevel::File,
    SetupLevel::Function,
    SetupLevel::Execution,
];

/// Return `level` and all levels nested inside it.
fn levels_from(level: SetupLevel) -> &'static [SetupLevel] {
    match level {
        SetupLevel::Session => &LEVEL_ORDER,
        SetupLevel::File => &LEVEL_ORDER[1..],
        SetupLevel::Function => &LEVEL_ORDER[2..],
        SetupLevel::Execution => &LEVEL_ORDER[3..],
    }
}

// ---------------------------------------------------------------------------
// Implement Hash for SetupLevel so it can be used as HashMap key
// ---------------------------------------------------------------------------

// SetupLevel already derives Eq + Copy; it needs Hash for use in HashMap.
// The derive is in protocol.rs — if it's missing we implement it here.
// Checked: protocol.rs does NOT derive Hash, so we provide it.
impl std::hash::Hash for SetupLevel {
    fn hash<H: std::hash::Hasher>(&self, state: &mut H) {
        (*self as u8).hash(state);
    }
}

