#[cfg(test)]
mod tests {
    use super::*;

    // -- SetupTimeouts ------------------------------------------------------

    #[test]
    fn timeouts_default_values() {
        let t = SetupTimeouts::default();
        assert_eq!(t.session, Duration::from_secs(DEFAULT_SESSION_TIMEOUT_SECS));
        assert_eq!(t.file, Duration::from_secs(DEFAULT_FILE_TIMEOUT_SECS));
        assert_eq!(
            t.function,
            Duration::from_secs(DEFAULT_FUNCTION_TIMEOUT_SECS)
        );
        assert_eq!(
            t.execution,
            Duration::from_secs(DEFAULT_EXECUTION_TIMEOUT_SECS)
        );
    }

    #[test]
    fn timeouts_timeout_for_matches_fields() {
        let t = SetupTimeouts::default();
        assert_eq!(t.timeout_for(SetupLevel::Session), t.session);
        assert_eq!(t.timeout_for(SetupLevel::File), t.file);
        assert_eq!(t.timeout_for(SetupLevel::Function), t.function);
        assert_eq!(t.timeout_for(SetupLevel::Execution), t.execution);
    }

    #[test]
    fn timeouts_from_env_valid_override() {
        unsafe {
            std::env::set_var(SETUP_TIMEOUT_ENV_VAR, "42");
        }
        let t = SetupTimeouts::from_env();
        let expected = Duration::from_secs(42);
        assert_eq!(t.session, expected);
        assert_eq!(t.file, expected);
        assert_eq!(t.function, expected);
        assert_eq!(t.execution, expected);
        unsafe {
            std::env::remove_var(SETUP_TIMEOUT_ENV_VAR);
        }
    }

    #[test]
    fn timeouts_from_env_invalid_falls_back() {
        unsafe {
            std::env::set_var(SETUP_TIMEOUT_ENV_VAR, "not_a_number");
        }
        let t = SetupTimeouts::from_env();
        assert_eq!(t, SetupTimeouts::default());
        unsafe {
            std::env::remove_var(SETUP_TIMEOUT_ENV_VAR);
        }
    }

    #[test]
    fn timeouts_from_env_zero_falls_back() {
        unsafe {
            std::env::set_var(SETUP_TIMEOUT_ENV_VAR, "0");
        }
        let t = SetupTimeouts::from_env();
        assert_eq!(t, SetupTimeouts::default());
        unsafe {
            std::env::remove_var(SETUP_TIMEOUT_ENV_VAR);
        }
    }

    // -- SetupFailures ------------------------------------------------------

    #[test]
    fn failures_empty_by_default() {
        let f = SetupFailures::new();
        assert!(!f.has_failures(SetupLevel::Session));
        assert_eq!(f.total(), 0);
        assert!(f.failures_for(SetupLevel::File).is_empty());
    }

    #[test]
    fn failures_record_and_query() {
        let mut f = SetupFailures::new();
        f.record(
            SetupLevel::File,
            "test.ts".into(),
            "connection refused".into(),
        );
        assert!(f.has_failures(SetupLevel::File));
        assert!(!f.has_failures(SetupLevel::Session));
        assert_eq!(f.total(), 1);
        assert_eq!(f.failures_for(SetupLevel::File).len(), 1);
        assert_eq!(f.failures_for(SetupLevel::File)[0].scope, "test.ts");
    }

    #[test]
    fn failures_clear() {
        let mut f = SetupFailures::new();
        f.record(SetupLevel::Session, "s".into(), "err".into());
        f.clear();
        assert_eq!(f.total(), 0);
    }

    // -- SetupManager -------------------------------------------------------

    #[test]
    fn setup_and_context_stack() {
        let mut mgr = SetupManager::default();
        mgr.setup(
            SetupLevel::Session,
            "global",
            serde_json::json!({"db": "test"}),
        )
        .unwrap();
        mgr.setup(
            SetupLevel::Function,
            "fn_a",
            serde_json::json!({"fn": "a"}),
        )
        .unwrap();

        let stack = mgr.context_stack();
        assert_eq!(stack.contexts.len(), 2);
        assert_eq!(stack.contexts[0].level, SetupLevel::Session);
        assert_eq!(stack.contexts[1].level, SetupLevel::Function);
    }

    #[test]
    fn teardown_clears_inner_levels() {
        let mut mgr = SetupManager::default();
        mgr.setup(SetupLevel::Session, "s", serde_json::json!(1))
            .unwrap();
        mgr.setup(SetupLevel::File, "f", serde_json::json!(2))
            .unwrap();
        mgr.setup(SetupLevel::Function, "fn", serde_json::json!(3))
            .unwrap();
        mgr.setup(SetupLevel::Execution, "ex", serde_json::json!(4))
            .unwrap();

        mgr.teardown(SetupLevel::File);

        assert!(mgr.context_for(SetupLevel::Session).is_some());
        assert!(mgr.context_for(SetupLevel::File).is_none());
        assert!(mgr.context_for(SetupLevel::Function).is_none());
        assert!(mgr.context_for(SetupLevel::Execution).is_none());
    }

    #[test]
    fn should_skip_due_to_outer_failure() {
        let mut mgr = SetupManager::default();
        mgr.record_failure(SetupLevel::File, "test.ts", "db error".into())
            .unwrap();

        assert!(mgr.should_skip(SetupLevel::File));
        assert!(mgr.should_skip(SetupLevel::Function));
        assert!(mgr.should_skip(SetupLevel::Execution));
        assert!(!mgr.should_skip(SetupLevel::Session));
    }

    #[test]
    fn setup_rejected_when_outer_failure_exists() {
        let mut mgr = SetupManager::default();
        mgr.record_failure(SetupLevel::Session, "global", "timeout".into())
            .unwrap();

        let result = mgr.setup(SetupLevel::Function, "fn_a", serde_json::json!(null));
        assert!(result.is_err());
        match result.unwrap_err() {
            SetupError::Skipped { failed_level, .. } => {
                assert_eq!(failed_level, SetupLevel::Session);
            }
            other => panic!("expected Skipped, got {other:?}"),
        }
    }

    #[test]
    fn fail_on_error_propagates_immediately() {
        let mut mgr = SetupManager::new(SetupTimeouts::default(), true);
        let result = mgr.record_failure(SetupLevel::Function, "fn_a", "oops".into());
        assert!(result.is_err());
        match result.unwrap_err() {
            SetupError::Failed { level, .. } => {
                assert_eq!(level, SetupLevel::Function);
            }
            other => panic!("expected Failed, got {other:?}"),
        }
    }

    #[test]
    fn fail_on_error_false_records_silently() {
        let mut mgr = SetupManager::new(SetupTimeouts::default(), false);
        mgr.record_failure(SetupLevel::Function, "fn_a", "oops".into())
            .unwrap();
        assert!(mgr.failures.has_failures(SetupLevel::Function));
    }

    #[test]
    fn context_for_returns_cached_value() {
        let mut mgr = SetupManager::default();
        let ctx = serde_json::json!({"key": "value"});
        mgr.setup(SetupLevel::File, "f", ctx.clone()).unwrap();
        assert_eq!(mgr.context_for(SetupLevel::File), Some(&ctx));
        assert_eq!(mgr.context_for(SetupLevel::Session), None);
    }

    #[test]
    fn setup_replaces_existing_context() {
        let mut mgr = SetupManager::default();
        mgr.setup(SetupLevel::File, "f", serde_json::json!(1))
            .unwrap();
        mgr.setup(SetupLevel::File, "f", serde_json::json!(2))
            .unwrap();
        assert_eq!(
            mgr.context_for(SetupLevel::File),
            Some(&serde_json::json!(2))
        );
    }

    #[test]
    fn has_active_contexts_tracks_state() {
        let mut mgr = SetupManager::default();
        assert!(!mgr.has_active_contexts());
        mgr.setup(SetupLevel::Session, "s", serde_json::json!(1))
            .unwrap();
        assert!(mgr.has_active_contexts());
        mgr.teardown(SetupLevel::Session);
        assert!(!mgr.has_active_contexts());
    }

    #[test]
    fn timeout_for_delegates_to_timeouts() {
        let mgr = SetupManager::default();
        assert_eq!(
            mgr.timeout_for(SetupLevel::Session),
            Duration::from_secs(DEFAULT_SESSION_TIMEOUT_SECS)
        );
    }

    #[test]
    fn context_stack_ordering() {
        let mut mgr = SetupManager::default();
        // Insert in reverse order — stack should still be outermost-first.
        mgr.setup(SetupLevel::Execution, "ex", serde_json::json!("e"))
            .unwrap();
        mgr.setup(SetupLevel::Session, "s", serde_json::json!("s"))
            .unwrap();

        let stack = mgr.context_stack();
        assert_eq!(stack.contexts[0].level, SetupLevel::Session);
        assert_eq!(stack.contexts[1].level, SetupLevel::Execution);
    }

    // -- Proptest -----------------------------------------------------------

    mod proptests {
        use super::*;
        use proptest::prelude::*;

        fn arb_setup_level() -> impl Strategy<Value = SetupLevel> {
            prop_oneof![
                Just(SetupLevel::Session),
                Just(SetupLevel::File),
                Just(SetupLevel::Function),
                Just(SetupLevel::Execution),
            ]
        }

        fn arb_timeout_secs() -> impl Strategy<Value = u64> {
            1..=3600u64
        }

        proptest! {
            /// All default timeouts are positive.
            #[test]
            fn default_timeouts_all_positive(_level in arb_setup_level()) {
                let t = SetupTimeouts::default();
                prop_assert!(t.session > Duration::ZERO);
                prop_assert!(t.file > Duration::ZERO);
                prop_assert!(t.function > Duration::ZERO);
                prop_assert!(t.execution > Duration::ZERO);
            }

            /// timeout_for always returns a value consistent with the struct fields.
            #[test]
            fn timeout_for_consistent(
                s in arb_timeout_secs(),
                f in arb_timeout_secs(),
                func in arb_timeout_secs(),
                e in arb_timeout_secs(),
                level in arb_setup_level(),
            ) {
                let t = SetupTimeouts {
                    session: Duration::from_secs(s),
                    file: Duration::from_secs(f),
                    function: Duration::from_secs(func),
                    execution: Duration::from_secs(e),
                };
                let expected = match level {
                    SetupLevel::Session => t.session,
                    SetupLevel::File => t.file,
                    SetupLevel::Function => t.function,
                    SetupLevel::Execution => t.execution,
                };
                prop_assert_eq!(t.timeout_for(level), expected);
            }

            /// Recording a failure at a level makes should_skip true for that
            /// level and all inner levels, but not outer ones.
            #[test]
            fn should_skip_respects_hierarchy(level in arb_setup_level()) {
                let mut mgr = SetupManager::default();
                mgr.record_failure(level, "scope", "err".into()).unwrap();

                let idx = LEVEL_ORDER.iter().position(|&l| l == level).unwrap();
                for (i, &lvl) in LEVEL_ORDER.iter().enumerate() {
                    if i < idx {
                        prop_assert!(!mgr.should_skip(lvl),
                            "outer level {lvl:?} should not be skipped when {level:?} failed");
                    } else {
                        prop_assert!(mgr.should_skip(lvl),
                            "level {lvl:?} should be skipped when {level:?} failed");
                    }
                }
            }

            /// Teardown at a level removes that level and all inner, keeps outer.
            #[test]
            fn teardown_preserves_outer(level in arb_setup_level()) {
                let mut mgr = SetupManager::default();
                for &lvl in &LEVEL_ORDER {
                    mgr.setup(lvl, "x", serde_json::json!(1)).unwrap();
                }
                mgr.teardown(level);

                let idx = LEVEL_ORDER.iter().position(|&l| l == level).unwrap();
                for (i, &lvl) in LEVEL_ORDER.iter().enumerate() {
                    if i < idx {
                        prop_assert!(mgr.context_for(lvl).is_some(),
                            "outer level {lvl:?} should be preserved");
                    } else {
                        prop_assert!(mgr.context_for(lvl).is_none(),
                            "level {lvl:?} should be cleared");
                    }
                }
            }

            /// Context stack is always ordered outermost-first regardless of
            /// insertion order.
            #[test]
            fn context_stack_always_ordered(
                levels in prop::collection::vec(arb_setup_level(), 1..=4)
            ) {
                let mut mgr = SetupManager::default();
                for lvl in levels {
                    let _ = mgr.setup(lvl, "x", serde_json::json!(1));
                }
                let stack = mgr.context_stack();
                for window in stack.contexts.windows(2) {
                    let idx0 = LEVEL_ORDER.iter().position(|&l| l == window[0].level).unwrap();
                    let idx1 = LEVEL_ORDER.iter().position(|&l| l == window[1].level).unwrap();
                    prop_assert!(idx0 < idx1,
                        "context stack not ordered: {:?} before {:?}", window[0].level, window[1].level);
                }
            }

            /// SetupFailures.total equals the sum of per-level counts.
            #[test]
            fn failures_total_consistent(
                counts in prop::collection::vec((arb_setup_level(), 0..5usize), 1..=8)
            ) {
                let mut f = SetupFailures::new();
                let mut expected_total = 0usize;
                for (level, count) in &counts {
                    for i in 0..*count {
                        f.record(*level, format!("s{i}"), "err".into());
                        expected_total += 1;
                    }
                }
                prop_assert_eq!(f.total(), expected_total);
            }
        }
    }
